import{_ as e,o as a,c as t,O as r}from"./chunks/framework.bdcb0ee1.js";const m=JSON.parse('{"title":"User Approvals","description":"","frontmatter":{},"headers":[],"relativePath":"administration/users/user-approvals.md","filePath":"administration/users/user-approvals.md","lastUpdated":1773167338000}'),s={name:"administration/users/user-approvals.md"},i=r('<h1 id="user-approvals" tabindex="-1">User Approvals <a class="header-anchor" href="#user-approvals" aria-label="Permalink to &quot;User Approvals&quot;">​</a></h1><p>When <strong>manual approval</strong> is enabled for new registrations, administrators must manually approve each user before they can access the forum.</p><h2 id="what-happens-when-a-user-registers" tabindex="-1">What happens when a user registers <a class="header-anchor" href="#what-happens-when-a-user-registers" aria-label="Permalink to &quot;What happens when a user registers&quot;">​</a></h2><ul><li>The user is <strong>blocked from logging in</strong> until approved.</li><li>The user is <strong>not allocated a member number</strong> until approval.</li><li>A notification is sent to all administrators informing them that a new user is awaiting approval.</li></ul><h2 id="reviewing-pending-users" tabindex="-1">Reviewing pending users <a class="header-anchor" href="#reviewing-pending-users" aria-label="Permalink to &quot;Reviewing pending users&quot;">​</a></h2><p>Clicking the link in the admin notification will take you directly to the <strong>user edit page</strong> in the Admin CP.</p><p>From there, you can choose to:</p><ul><li><p><strong>Approve</strong> the user:</p><ul><li>The user is assigned a member number.</li><li>An approval confirmation email is sent to the user.</li><li>The user can now log in and access the forum.</li></ul></li><li><p><strong>Deny</strong> the user:</p><ul><li>The account is immediately deleted.</li><li>No further action is required.</li></ul></li></ul><blockquote><p>Note: This process is one-time. Once approved or denied, the account status cannot be reverted.</p></blockquote><h2 id="related-settings" tabindex="-1">Related Settings <a class="header-anchor" href="#related-settings" aria-label="Permalink to &quot;Related Settings&quot;">​</a></h2><p>Manual approval can be enabled or disabled from the <a href="/administration/config/settings.html">Board Settings</a> section under the <strong>Registrations</strong> section.</p>',11),n=[i];function o(l,p,u,h,d,c){return a(),t("div",null,n)}const _=e(s,[["render",o]]);export{m as __pageData,_ as default};
